import{c as a,a7 as e,y as d,B as r}from"./chunks/framework.3cjvm90C.js";const p=JSON.parse('{"title":"脑海 2B 模型 GRPO 强化微调","description":"记录脑海 2B 模型使用 GRPO 方法在 GSM8k 数据集上进行强化微调的超参数配置与训练结果","frontmatter":{"title":"脑海 2B 模型 GRPO 强化微调","description":"记录脑海 2B 模型使用 GRPO 方法在 GSM8k 数据集上进行强化微调的超参数配置与训练结果"},"headers":[],"relativePath":"ascend/naohai_2b_rl.md","filePath":"ascend/naohai_2b_rl.md","lastUpdated":1782447613000}'),l={name:"ascend/naohai_2b_rl.md"};function i(n,t,o,h,s,_){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="脑海-2b-模型-grpo-强化微调" tabindex="-1">脑海 2B 模型 GRPO 强化微调 <a class="header-anchor" href="#脑海-2b-模型-grpo-强化微调" aria-label="Permalink to “脑海 2B 模型 GRPO 强化微调”">​</a></h1><h2 id="模型和数据" tabindex="-1">模型和数据 <a class="header-anchor" href="#模型和数据" aria-label="Permalink to “模型和数据”">​</a></h2><ul><li>Model：Naohai-2B</li><li>Train Dataset：GSM8k Train</li><li>Evaluation Dataset：GSM8k Test</li></ul><h2 id="训练超参数" tabindex="-1">训练超参数 <a class="header-anchor" href="#训练超参数" aria-label="Permalink to “训练超参数”">​</a></h2><table tabindex="0"><thead><tr><th>超参数</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>advantage_estimator</td><td>grpo_norm</td><td>GRPO 优势估计方法</td></tr><tr><td>n_samples_per_prompt</td><td>8</td><td>每个 prompt 生成的样本数</td></tr><tr><td>prompt_max_len</td><td>1024</td><td>最大 prompt 长度</td></tr><tr><td>generate_max_len</td><td>1024</td><td>最大生成长度</td></tr><tr><td>micro_train_batch_size</td><td>4</td><td>每个 GPU 的训练微批大小</td></tr><tr><td>train_batch_size</td><td>256</td><td>全局训练批大小</td></tr><tr><td>data_type</td><td>bf16</td><td>模型参数类型</td></tr><tr><td>actor_learning_rate</td><td>5e-7</td><td>Actor 模型学习率</td></tr><tr><td>use_kl_loss</td><td>False</td><td>是否使用 KL 损失</td></tr><tr><td>init_kl_coef</td><td>0</td><td>KL 损失系数初始值</td></tr></tbody></table><h2 id="训练曲线" tabindex="-1">训练曲线 <a class="header-anchor" href="#训练曲线" aria-label="Permalink to “训练曲线”">​</a></h2><h3 id="reward-曲线" tabindex="-1">Reward 曲线 <a class="header-anchor" href="#reward-曲线" aria-label="Permalink to “Reward 曲线”">​</a></h3><p>训练过程中的奖励曲线显示了模型性能的稳定提升：</p><ul><li>初始阶段奖励值较低</li><li>中期阶段有明显上升趋势</li><li>后期趋于稳定，说明模型收敛</li></ul><h3 id="response-length-曲线" tabindex="-1">Response Length 曲线 <a class="header-anchor" href="#response-length-曲线" aria-label="Permalink to “Response Length 曲线”">​</a></h3><p>响应长度曲线反映了模型输出的变化：</p><ul><li>随着训练进行，响应长度先上升后下降。</li><li>最终阶段长度趋于稳定，表明模型学会了更详细的推理过程。</li></ul><h2 id="评估结果" tabindex="-1">评估结果 <a class="header-anchor" href="#评估结果" aria-label="Permalink to “评估结果”">​</a></h2><table tabindex="0"><thead><tr><th>模型</th><th>GSM8K Test 准确率</th></tr></thead><tbody><tr><td>NaoHai2B Base</td><td>59.0%</td></tr><tr><td>NaoHai2B Base + GRPO</td><td>74.5%</td></tr></tbody></table><p>性能提升分析： 基础模型在 GSM8K 测试集上达到 59.0% 的准确率， 经过 GRPO 强化微调后，准确率提升至 74.5%， 总体提升 15.5 个百分点，显示 GRPO 训练的有效性。</p>',15)])])}const b=a(l,[["render",i]]);export{p as __pageData,b as default};
